#' Build a unified vector presence dataset
#'
#' Combines previously prepared Mosquito Alert and/or GBIF vector observations
#' for a given location into a single presence-only dataset with harmonised
#' columns. The helper looks for the size-specific vector files generated by
#' `get_malert_data()` and `get_gbif_data()` and merges them when requested.
#'
#' @param iso3 Three-letter ISO3 country code used in the vector filenames.
#' @param admin_level Administrative level included in the vector filenames.
#' @param admin_name Administrative unit name used in the vector filenames.
#' @param sources Character vector specifying which vector sources to include.
#'   Accepted values are `"malert"`, `"gbif"`, or both. Default includes both.
#' @param vector_dirs Character vector of directories to search for the prepared
#'   vector files. Defaults to `"data/proc"`.
#' @param output_dir Directory where the combined dataset will be saved.
#'   Defaults to `"data/proc"`.
#' @param overwrite Logical; set to `TRUE` to overwrite an existing output file.
#'   Defaults to `FALSE`.
#' @param exclude_collection_on_merge Character vector of GBIF `collectionCode`
#'   values to drop when both sources are merged. Defaults to discarding
#'   `"Mosquito Alert Tiger Mosquito"` when Mosquito Alert data is present. Use
#'   `NULL` to keep all collection codes.
#'
#' @return A tibble with columns `date`, `year`, `lon`, `lat`,
#'   `presence`, `referenceID`, and `source`. Attributes include `output_path`
#'   and `source_files`.
#' @export
initialize_vector_dataset <- function(
	iso3,
	admin_level,
	admin_name,
	sources = c("malert", "gbif"),
	vector_dirs = "data/proc",
	output_dir = "data/proc",
	overwrite = FALSE,
	exclude_collection_on_merge = "Mosquito Alert Tiger Mosquito"
) {
	valid_sources <- c("malert", "gbif")
	if (missing(sources) || is.null(sources)) {
		sources <- valid_sources
	}
	sources <- unique(tolower(sources))
	unknown <- setdiff(sources, valid_sources)
	if (length(unknown)) {
		stop("Unsupported vector source(s): ", paste(unknown, collapse = ", "), call. = FALSE)
	}
	if (!length(sources)) {
		stop("At least one vector source must be specified.", call. = FALSE)
	}

	ids <- build_location_identifiers(toupper(iso3), admin_level, admin_name)
	slug <- ids$slug

	normalise_name <- function(x) {
		tolower(gsub("[^a-z0-9]", "", x))
	}

	find_column <- function(data, candidates) {
		names_norm <- normalise_name(names(data))
		for (cand in candidates) {
			idx <- which(names_norm == normalise_name(cand))
			if (length(idx)) {
				return(names(data)[idx[1]])
			}
		}
		NA_character_
	}

	read_vector_file <- function(filename) {
		candidate_paths <- file.path(vector_dirs, filename)
		existing <- candidate_paths[file.exists(candidate_paths)]
		if (!length(existing)) {
			stop(
				"Vector file not found. Looked for: ",
				paste(candidate_paths, collapse = "; "),
				call. = FALSE
			)
		}
		list(
			data = tibble::as_tibble(readRDS(existing[1])),
			path = existing[1]
		)
	}

	to_date <- function(x) {
		if (inherits(x, "Date")) {
			return(as.Date(x))
		}
		x_chr <- trimws(as.character(x))
		x_chr <- sub("T.*$", "", x_chr)
		x_chr[x_chr == ""] <- NA_character_
		as.Date(x_chr)
	}

	make_template <- function() {
		tibble::tibble(
			date = as.Date(character()),
			year = integer(),
			lon = numeric(),
			lat = numeric(),
			presence = character(),
			referenceID = character(),
			source = character()
		)
	}

	source_data <- list()
	source_paths <- list()

	if ("malert" %in% sources) {
		malert_file <- sprintf("vector_%s_malert.Rds", slug)
		malert_list <- read_vector_file(malert_file)
		malert_data <- malert_list$data
		source_paths$malert <- malert_list$path
		message("Loaded Mosquito Alert vector data from ", malert_list$path)

		mapped <- list(
			date_col = find_column(malert_data, "creation_date"),
			year_col = find_column(malert_data, "creation_year"),
			lon_col = find_column(malert_data, c("lon", "longitude")),
			lat_col = find_column(malert_data, c("lat", "latitude")),
			ref_col = find_column(malert_data, c("version_UUID", "report_uuid"))
		)
		missing_required <- Filter(is.na, mapped)
		if (length(missing_required)) {
			stop("Required columns missing from Mosquito Alert data: ",
				paste(names(missing_required), collapse = ", "),
				call. = FALSE
			)
		}

		malert_prepped <- tibble::tibble(
			date = to_date(malert_data[[mapped$date_col]]),
			year = as.integer(malert_data[[mapped$year_col]]),
			lon = as.numeric(malert_data[[mapped$lon_col]]),
			lat = as.numeric(malert_data[[mapped$lat_col]]),
			presence = rep("TRUE", nrow(malert_data)),
			referenceID = as.character(malert_data[[mapped$ref_col]]),
			source = "malert"
		)

		source_data$malert <- malert_prepped
	}

	if ("gbif" %in% sources) {
		gbif_file <- sprintf("vector_%s_gbif.Rds", slug)
		gbif_list <- read_vector_file(gbif_file)
		gbif_data <- gbif_list$data
		source_paths$gbif <- gbif_list$path
		message("Loaded GBIF vector data from ", gbif_list$path)

		# Optional exclusion of specific collection codes when merging
		if (length(sources) > 1 && !is.null(exclude_collection_on_merge)) {
			collection_col <- find_column(gbif_data, "collectionCode")
			if (!is.na(collection_col)) {
				exclude_mask <- gbif_data[[collection_col]] %in% exclude_collection_on_merge
				rows_excluded <- sum(exclude_mask, na.rm = TRUE)
				if (rows_excluded) {
					message("Excluding ", rows_excluded, " GBIF record(s) with collectionCode in ",
						paste(exclude_collection_on_merge, collapse = ", ")
					)
					gbif_data <- gbif_data[!exclude_mask | is.na(exclude_mask), , drop = FALSE]
				}
			}
		}

		mapped <- list(
			date_col = find_column(gbif_data, c("event_date", "eventDate")),
			year_col = find_column(gbif_data, "year"),
			lon_col = find_column(gbif_data, c("decimal_longitude", "decimalLongitude")),
			lat_col = find_column(gbif_data, c("decimal_latitude", "decimalLatitude")),
			presence_col = find_column(gbif_data, c("occurrence_status", "occurrenceStatus")),
			ref_col = find_column(gbif_data, c("occurrence_id", "occurrenceID"))
		)
		missing_required <- Filter(is.na, mapped[c("date_col", "year_col", "lon_col", "lat_col", "ref_col")])
		if (length(missing_required)) {
			stop("Required columns missing from GBIF data: ",
				paste(names(missing_required), collapse = ", "),
				call. = FALSE
			)
		}

		presence_values <- rep(NA_character_, nrow(gbif_data))
		if (!is.na(mapped$presence_col)) {
			raw_presence <- tolower(trimws(as.character(gbif_data[[mapped$presence_col]])))
			presence_values[raw_presence %in% c("present", "true", "1")] <- "TRUE"
			presence_values[raw_presence %in% c("absent", "false", "0")] <- "FALSE"
		}

		gbif_prepped <- tibble::tibble(
			date = to_date(gbif_data[[mapped$date_col]]),
			year = as.integer(gbif_data[[mapped$year_col]]),
			lon = as.numeric(gbif_data[[mapped$lon_col]]),
			lat = as.numeric(gbif_data[[mapped$lat_col]]),
			presence = presence_values,
			referenceID = as.character(gbif_data[[mapped$ref_col]]),
			source = "gbif"
		)

		source_data$gbif <- gbif_prepped
	}

	template <- make_template()
	if (!length(source_data)) {
		warning("No vector data sources were loaded; returning an empty dataset.", call. = FALSE)
		return(template)
	}

	combined <- dplyr::bind_rows(source_data)

	ordered_sources <- intersect(valid_sources, names(source_data))
	suffix <- paste(ordered_sources, collapse = "_")
	output_filename <- sprintf("model_prep_%s_%s.Rds", slug, suffix)
	output_path <- file.path(output_dir, output_filename)

	if (file.exists(output_path) && !isTRUE(overwrite)) {
		stop("Output already exists at ", output_path, " (set overwrite = TRUE to replace it).", call. = FALSE)
	}

	dir.create(dirname(output_path), recursive = TRUE, showWarnings = FALSE)
	saveRDS(combined, output_path)
	message("Saved combined vector dataset to ", output_path)

	attr(combined, "output_path") <- output_path
	attr(combined, "source_files") <- unlist(source_paths[ordered_sources], use.names = TRUE)

	combined
}
